// ==================== LAYOUT COMPONENT ====================

const Layout = ({ children }) => {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const { user, logout } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const menuItems = [
    { text: 'Dashboard', icon: <Dashboard />, path: '/dashboard' },
    { text: 'Upload Resume', icon: <Upload />, path: '/upload' },
    { text: 'ATS Analysis', icon: <Assessment />, path: '/analyze' },
    { text: 'Job Matcher', icon: <Work />, path: '/match' },
    { text: 'History', icon: <History />, path: '/history' },
  ];

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
        <Toolbar>
          <IconButton
            color="inherit"
            edge="start"
            onClick={() => setDrawerOpen(true)}
            sx={{ mr: 2, display: { sm: 'none' } }}
          >
            <MenuIcon />
          </IconButton>
          <Analytics sx={{ mr: 2 }} />
          <Typography variant="h6" sx={{ flexGrow: 1, cursor: 'pointer' }} onClick={() => navigate('/')}>
            Resume Analyzer
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <Typography variant="body2">{user?.username}</Typography>
            <IconButton color="inherit" onClick={handleLogout}>
              <Logout />
            </IconButton>
          </Box>
        </Toolbar>
      </AppBar>

      <Drawer
        variant="permanent"
        sx={{
          display: { xs: 'none', sm: 'block' },
          '& .MuiDrawer-paper': {
            width: 280,
            boxSizing: 'border-box',
            mt: 8,
          },
        }}
        open
      >
        <List>
          {menuItems.map((item) => (
            <ListItem
              button
              key={item.text}
              onClick={() => navigate(item.path)}
              sx={{
                mx: 1,
                borderRadius: 2,
              }}
            >
              <ListItemIcon>{item.icon}</ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItem>
          ))}
        </List>
      </Drawer>

      <Drawer
        variant="temporary"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
        sx={{ display: { xs: 'block', sm: 'none' } }}
      >
        <List>
          {menuItems.map((item) => (
            <ListItem
              button
              key={item.text}
              onClick={() => {
                navigate(item.path);
                setDrawerOpen(false);
              }}
            >
              <ListItemIcon>{item.icon}</ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItem>
          ))}
        </List>
      </Drawer>

      <Box
        component="main"
        sx={{
          flexGrow: 1,
          p: 3,
          mt: 8,
          backgroundColor: '#f8fafc',
          minHeight: '100vh',
        }}
      >
        {children}
      </Box>
    </Box>
  );
};

// ==================== LOGIN PAGE ====================

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await login(username, password);
      navigate('/dashboard');
    } catch (error) {
      setError(error.response?.data?.detail || 'Invalid username or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      }}
    >
      <Card sx={{ maxWidth: 400, width: '100%', mx: 2 }}>
        <CardContent sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Analytics sx={{ fontSize: 48, color: 'primary.main' }} />
            <Typography variant="h4" gutterBottom>
              Welcome Back
            </Typography>
            <Typography color="text.secondary">
              Sign in to your account
            </Typography>
          </Box>

          <form onSubmit={handleSubmit}>
            <TextField
              fullWidth
              label="Username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              margin="normal"
              required
            />
            {error && (
              <Alert severity="error" sx={{ mt: 2 }}>
                {error}
              </Alert>
            )}
            <Button
              type="submit"
              fullWidth
              variant="contained"
              size="large"
              disabled={loading}
              sx={{ mt: 3 }}
            >
              {loading ? <CircularProgress size={24} /> : 'Sign In'}
            </Button>
          </form>

          <Box textAlign="center" mt={2}>
            <Typography variant="body2" color="text.secondary">
              Don't have an account?{' '}
              <Button component={Link} to="/signup" size="small">
                Sign Up
              </Button>
            </Typography>
          </Box>
        </CardContent>
      </Card>
    </Box>
  );
};

// ==================== SIGNUP PAGE ====================

const SignupPage = () => {
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signup(formData);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2000);
    } catch (error) {
      setError(error.response?.data?.detail || 'Signup failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      }}
    >
      <Card sx={{ maxWidth: 400, width: '100%', mx: 2 }}>
        <CardContent sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Analytics sx={{ fontSize: 48, color: 'primary.main' }} />
            <Typography variant="h4" gutterBottom>
              Create Account
            </Typography>
            <Typography color="text.secondary">
              Sign up to get started with AI resume analysis
            </Typography>
          </Box>

          <form onSubmit={handleSubmit}>
            <TextField
              fullWidth
              label="Username"
              value={formData.username}
              onChange={(e) => setFormData({ ...formData, username: e.target.value })}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Email"
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Password"
              type="password"
              value={formData.password}
              onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              margin="normal"
              required
            />
            {error && (
              <Alert severity="error" sx={{ mt: 2 }}>
                {error}
              </Alert>
            )}
            {success && (
              <Alert severity="success" sx={{ mt: 2 }}>
                Account created successfully! Redirecting to login...
              </Alert>
            )}
            <Button
              type="submit"
              fullWidth
              variant="contained"
              size="large"
              disabled={loading}
              sx={{ mt: 3 }}
            >
              {loading ? <CircularProgress size={24} /> : 'Sign Up'}
            </Button>
          </form>

          <Box textAlign="center" mt={2}>
            <Typography variant="body2" color="text.secondary">
              Already have an account?{' '}
              <Button component={Link} to="/login" size="small">
                Sign In
              </Button>
            </Typography>
          </Box>
        </CardContent>
      </Card>
    </Box>
  );
};

// ==================== DASHBOARD PAGE ====================

const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalResumes: 0,
    averageScore: 0,
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const resumesRes = await api.get('/resume/list');
      const historyRes = await api.get('/analysis/history');

      setResumes(resumesRes.data);

      const atsAnalyses = historyRes.data.filter(a => a.analysis_type === 'ats_score');
      const avgScore = atsAnalyses.reduce((sum, a) => sum + (a.ats_score || 0), 0) / (atsAnalyses.length || 1);

      setStats({
        totalResumes: resumesRes.data.length,
        averageScore: Math.round(avgScore),
      });
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Dashboard
      </Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Track your resume performance and job matching progress
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Box display="flex" alignItems="center" justifyContent="space-between">
                <Box>
                  <Typography color="text.secondary" gutterBottom>
                    Total Resumes
                  </Typography>
                  <Typography variant="h3">{stats.totalResumes}</Typography>
                </Box>
                <Description sx={{ fontSize: 48, color: 'primary.main', opacity: 0.7 }} />
              </Box>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Box display="flex" alignItems="center" justifyContent="space-between">
                <Box>
                  <Typography color="text.secondary" gutterBottom>
                    Average ATS Score
                  </Typography>
                  <Typography variant="h3">{stats.averageScore}%</Typography>
                </Box>
                <TrendingUp sx={{ fontSize: 48, color: 'success.main', opacity: 0.7 }} />
              </Box>
              <LinearProgress
                variant="determinate"
                value={stats.averageScore}
                sx={{ mt: 2, height: 8, borderRadius: 4 }}
              />
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Recent Resumes
      </Typography>
      <Grid container spacing={2}>
        {resumes.slice(0, 3).map((resume) => (
          <Grid item xs={12} md={4} key={resume.id}>
            <Card>
              <CardContent>
                <Typography variant="h6">{resume.name || 'Unnamed Resume'}</Typography>
                <Typography variant="body2" color="text.secondary">
                  {resume.filename}
                </Typography>
                <Box sx={{ mt: 2 }}>
                  {resume.skills?.slice(0, 3).map((skill) => (
                    <Chip key={skill} label={skill} size="small" sx={{ mr: 0.5, mb: 0.5 }} />
                  ))}
                </Box>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
};

// ==================== UPLOAD PAGE ====================

const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleUpload = async () => {
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a file' });
      return;
    }

    const formData = new FormData();
    formData.append('file', file);

    setUploading(true);
    try {
      const response = await api.post('/resume/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      setMessage({ type: 'success', text: 'Resume uploaded and parsed successfully!' });
      setTimeout(() => navigate('/dashboard'), 2000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.detail || 'Upload failed' });
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Upload Resume
      </Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Upload your resume in PDF or DOCX format for AI-powered analysis
      </Typography>

      <Card>
        <CardContent>
          <DropzoneArea
            acceptedFiles={['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document']}
            maxFileSize={10 * 1024 * 1024}
            filesLimit={1}
            onChange={(files) => setFile(files[0])}
            showAlerts={false}
          />

          <Box sx={{ mt: 3, display: 'flex', justifyContent: 'center' }}>
            <Button
              variant="contained"
              onClick={handleUpload}
              disabled={!file || uploading}
              startIcon={<CloudUpload />}
              size="large"
            >
              {uploading ? 'Uploading...' : 'Upload Resume'}
            </Button>
          </Box>

          {message.text && (
            <Alert severity={message.type} sx={{ mt: 2 }}>
              {message.text}
            </Alert>
          )}
        </CardContent>
      </Card>
    </Box>
  );
};

// ==================== ATS ANALYSIS PAGE ====================

const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [tabValue, setTabValue] = useState(0);

  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error fetching resumes:', error);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedResume) return;

    setAnalyzing(true);
    try {
      const response = await api.post('/analyze/ats', { resume_id: selectedResume });
      setAnalysis(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        ATS Analysis
      </Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Get AI-powered ATS score and improvement suggestions
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Select Resume
              </Typography>
              <List>
                {resumes.map((resume) => (
                  <ListItem
                    button
                    key={resume.id}
                    selected={selectedResume === resume.id}
                    onClick={() => setSelectedResume(resume.id)}
                    sx={{ borderRadius: 2, mb: 1 }}
                  >
                    <ListItemIcon>
                      <Description />
                    </ListItemIcon>
                    <ListItemText
                      primary={resume.name || resume.filename}
                      secondary={new Date(resume.uploaded_at).toLocaleDateString()}
                    />
                  </ListItem>
                ))}
              </List>
              {resumes.length === 0 && (
                <Typography color="text.secondary">No resumes uploaded yet</Typography>
              )}
              <Button
                variant="contained"
                fullWidth
                onClick={handleAnalyze}
                disabled={!selectedResume || analyzing}
                sx={{ mt: 2 }}
              >
                {analyzing ? <CircularProgress size={24} /> : 'Analyze'}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          {analysis && (
            <Card>
              <CardContent>
                <Box textAlign="center" mb={3}>
                  <Typography variant="h2" color="primary">
                    {Math.round(analysis.ats_score)}%
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    ATS Compatibility Score
                  </Typography>
                  <LinearProgress
                    variant="determinate"
                    value={analysis.ats_score}
                    sx={{ mt: 2, height: 10, borderRadius: 5 }}
                  />
                </Box>

                <Tabs value={tabValue} onChange={(e, v) => setTabValue(v)} sx={{ mb: 2 }}>
                  <Tab label="Strengths" />
                  <Tab label="Weaknesses" />
                  <Tab label="Missing Keywords" />
                  <Tab label="Suggestions" />
                </Tabs>

                <Box sx={{ mt: 2 }}>
                  {tabValue === 0 && (
                    <List>
                      {analysis.strengths?.map((strength, i) => (
                        <ListItem key={i}>
                          <CheckCircle color="success" sx={{ mr: 2 }} />
                          <Typography>{strength}</Typography>
                        </ListItem>
                      ))}
                    </List>
                  )}
                  {tabValue === 1 && (
                    <List>
                      {analysis.weaknesses?.map((weakness, i) => (
                        <ListItem key={i}>
                          <Error color="error" sx={{ mr: 2 }} />
                          <Typography>{weakness}</Typography>
                        </ListItem>
                      ))}
                    </List>
                  )}
                  {tabValue === 2 && (
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                      {analysis.missing_keywords?.map((keyword, i) => (
                        <Chip key={i} label={keyword} color="warning" />
                      ))}
                    </Box>
                  )}
                  {tabValue === 3 && (
                    <List>
                      {analysis.suggestions?.map((suggestion, i) => (
                        <ListItem key={i}>
                          <TrendingUp color="primary" sx={{ mr: 2 }} />
                          <Typography>{suggestion}</Typography>
                        </ListItem>
                      ))}
                    </List>
                  )}
                </Box>
              </CardContent>
            </Card>
          )}
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== JOB MATCHER PAGE ====================

const JobMatcherPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [jobDescription, setJobDescription] = useState('');
  const [match, setMatch] = useState(null);
  const [matching, setMatching] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);

  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error fetching resumes:', error);
    }
  };

  const handleMatch = async () => {
    if (!selectedResume || !jobDescription) return;

    setMatching(true);
    try {
      const response = await api.post('/analyze/match-job', {
        resume_id: selectedResume,
        job_description: jobDescription,
      });
      setMatch(response.data);
      setOpenDialog(true);
    } catch (error) {
      console.error('Matching error:', error);
    } finally {
      setMatching(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Job Matcher
      </Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Match your resume with job descriptions to find the best fit
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Select Resume
              </Typography>
              <List>
                {resumes.map((resume) => (
                  <ListItem
                    button
                    key={resume.id}
                    selected={selectedResume === resume.id}
                    onClick={() => setSelectedResume(resume.id)}
                    sx={{ borderRadius: 2, mb: 1 }}
                  >
                    <ListItemIcon>
                      <Description />
                    </ListItemIcon>
                    <ListItemText
                      primary={resume.name || resume.filename}
                      secondary={resume.skills?.slice(0, 2).join(', ')}
                    />
                  </ListItem>
                ))}
              </List>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Job Description
              </Typography>
              <TextField
                fullWidth
                multiline
                rows={10}
                variant="outlined"
                placeholder="Paste the job description here..."
                value={jobDescription}
                onChange={(e) => setJobDescription(e.target.value)}
              />
              <Button
                variant="contained"
                fullWidth
                onClick={handleMatch}
                disabled={!selectedResume || !jobDescription || matching}
                sx={{ mt: 2 }}
                size="large"
              >
                {matching ? <CircularProgress size={24} /> : 'Match with Job'}
              </Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          <Box display="flex" alignItems="center" justifyContent="space-between">
            <Typography variant="h5">Match Results</Typography>
            <Box textAlign="center">
              <Typography variant="h3" color="primary">
                {Math.round(match?.match_percentage || 0)}%
              </Typography>
              <Typography variant="body2">Match Score</Typography>
            </Box>
          </Box>
        </DialogTitle>
        <DialogContent>
          <Typography variant="h6" gutterBottom>
            Role Fit Summary
          </Typography>
          <Typography paragraph>{match?.role_fit_summary}</Typography>

          <Typography variant="h6" gutterBottom>
            Matched Skills
          </Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
            {match?.matched_skills?.map((skill, i) => (
              <Chip key={i} label={skill} color="success" icon={<CheckCircle />} />
            ))}
          </Box>

          <Typography variant="h6" gutterBottom>
            Missing Skills
          </Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
            {match?.missing_skills?.map((skill, i) => (
              <Chip key={i} label={skill} color="error" icon={<Error />} />
            ))}
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenDialog(false)}>Close</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

// ==================== HISTORY PAGE ====================

const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      const response = await api.get('/analysis/history');
      setHistory(response.data);
    } catch (error) {
      console.error('Error fetching history:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Analysis History
      </Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        View all your past resume analyses and job matches
      </Typography>

      <Grid container spacing={2}>
        {history.map((item) => (
          <Grid item xs={12} key={item.id}>
            <Card>
              <CardContent>
                <Box display="flex" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography variant="h6">{item.resume_name}</Typography>
                    <Typography variant="body2" color="text.secondary">
                      {new Date(item.created_at).toLocaleString()}
                    </Typography>
                    <Chip
                      label={item.analysis_type === 'ats_score' ? 'ATS Score' : 'Job Match'}
                      size="small"
                      sx={{ mt: 1 }}
                    />
                  </Box>
                  <Box textAlign="center">
                    {item.analysis_type === 'ats_score' ? (
                      <>
                        <Typography variant="h4" color="primary">
                          {Math.round(item.ats_score || 0)}%
                        </Typography>
                        <Typography variant="caption">ATS Score</Typography>
                      </>
                    ) : (
                      <>
                        <Typography variant="h4" color="secondary">
                          {Math.round(item.match_percentage || 0)}%
                        </Typography>
                        <Typography variant="caption">Match Rate</Typography>
                      </>
                    )}
                  </Box>
                </Box>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {history.length === 0 && (
        <Paper sx={{ p: 4, textAlign: 'center' }}>
          <Typography color="text.secondary">No analysis history yet</Typography>
          <Button
            variant="contained"
            component={Link}
            to="/upload"
            sx={{ mt: 2 }}
          >
            Upload Your First Resume
          </Button>
        </Paper>
      )}
    </Box>
  );
};

// ==================== MAIN APP ====================

const App = () => {
  const { user, loading } = React.useContext(AuthContext);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Router>
      <Routes>
        {/* Public Routes */}
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} />

        {/* Protected Routes */}
        <Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/match" element={user ? <Layout><JobMatcherPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
};

// ==================== APP WRAPPER ====================

const AppWrapper = () => {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <App />
      </AuthProvider>
    </ThemeProvider>
  );
};

export default AppWrapper;
